// vec is the 16-dim output of Vec.Vectorize(); only the first 14 dims are used (matching
// the training data from references.json.gz).
// Returns (fraudCount, true) only when the reached leaf is confident
// (majority class >= confidence threshold during training).
// Returns (0, false) for uncertain leaves — caller should fall through to k-NN.
func RawTreePredict(vec [16]float32) (int, bool) {
	node := int32(0)
	for rtLeft[node] != -1 {
		if vec[rtFeature[node]] <= rtThreshold[node] {
			node = rtLeft[node]
		} else {
			node = rtRight[node]
		}
	}
	if !rtConfident[node] {
		return 0, false
	}
	if rtClass[node] == 1 {
		return 5, true
	}
	return 0, true
}
